import { MockApiId } from './mockRegistry';
import type {
	ErrorResponseWrapped,
	FindMockOptions,
	HttpMethod,
	MockConfig,
	MockEndpoint,
	MockResponse,
	MockResponseId,
	NoDuplicateResponseIds,
	ResponseErrorDescription,
	ResponseWrappedData,
	ScenarioStep,
	StatusCode,
	UniqueMockId,
} from './types';
import type { ApiPath } from 'utils/generic';
import { allowedMocking, mockEndpoints, mockResponseOverrides, mockResponses, mockScenario } from './signals';
import { getCookieValue, LAB_MODE_COOKIE, MOCK_API } from 'utils/cookieStorage';
import { SCENARIOS } from './scenario';
import { createResponseObjectMap } from 'utils/mockapi/mapping/createResponseObjectMap';
import { createResponseIdMap, type ResponseObjectOverrides } from 'utils/mockapi/mapping/mapping';

const KNOWN_API_PATHS: ApiPath[] = ['/api/v1', '/api/v2', '/mkp/api/v1'];

export function makeCompositeId<A extends MockApiId, R extends MockResponseId>(apiId: A, responseId: R): `${A}-${R}` {
	return `${apiId}-${responseId}`;
}

export function makeResponse<A extends MockApiId, const R extends MockResponseId, T>(
	apiId: A,
	responseId: R,
	options: {
		label: string;
		code: StatusCode;
		data: T;
		note?: string;
		delay?: number;
	},
): MockResponse<T, `${A}-${R}`, R> {
	const uniqueId = makeCompositeId(apiId, responseId);

	return {
		responseId,
		uniqueId,
		...options,
	};
}

export function makeEndpoint<
	T,
	A extends MockApiId,
	R extends readonly [MockResponse<T>, ...MockResponse<T>[]],
>(config: {
	apiId: A;
	apiPath: ApiPath;
	method: HttpMethod;
	path: string;
	name: string;
	description: string;
	responses: R & NoDuplicateResponseIds<R>;
}): MockEndpoint {
	return config;
}

function getResponsesByEndpoint(apiPath: ApiPath, method: HttpMethod, path: string): MockResponse<any>[] {
	const endpoints = mockEndpoints.peek().length ? mockEndpoints.peek() : getAllMockEndpoints();
	const endpoint = endpoints.find(
		(ep: MockEndpoint) => ep.apiPath === apiPath && ep.method === method && ep.path === path,
	);
	return endpoint ? (endpoint.responses as MockResponse<any>[]) : [];
}

export function getMockResponsesFromCookie(cookieValue: string): UniqueMockId[] {
	if (!cookieValue) return [];

	try {
		const decoded = decodeURIComponent(cookieValue);
		const parsed = JSON.parse(decoded);

		if (isUniqueMockIdArray(parsed.r)) {
			return parsed.r;
		}
	} catch (e) {
		console.error(e);
		return [];
	}
	return [];
}

export function getMockScenarioFromCookie(cookieValue: string): ScenarioStep | undefined {
	if (!cookieValue) return undefined;

	try {
		const json = (() => {
			try {
				return decodeURIComponent(cookieValue);
			} catch {
				return cookieValue;
			}
		})();

		const parsed = JSON.parse(json);

		const candidate = parsed?.s as Record<string, unknown> | undefined;
		if (!candidate || typeof candidate !== 'object') return undefined;

		const rawScenarioId = candidate.scenarioId;
		const scenarioId =
			typeof rawScenarioId === 'string'
				? Number.parseInt(rawScenarioId, 10)
				: typeof rawScenarioId === 'number'
					? rawScenarioId
					: NaN;
		if (!Number.isInteger(scenarioId)) return undefined;

		const stepId =
			typeof candidate.stepId === 'number' && Number.isInteger(candidate.stepId) ? candidate.stepId : undefined;
		const scenario = SCENARIOS.find((s) => s.id === scenarioId);
		if (!scenario || scenario.steps.length === 0) return undefined;
		const step =
			(stepId !== undefined ? scenario.steps.find((st) => st.id === stepId) : undefined) ?? scenario.steps[0];
		if (!step || !isUniqueMockIdArray(step.mockResponses)) return undefined;
		return { scenarioId, stepId: step.id, mockResponses: step.mockResponses };
	} catch (e) {
		console.error(e);
		return undefined;
	}
}

export function getMockResponseOverridesFromCookie(cookieValue: string): Record<string, Record<string, string>> {
	if (!cookieValue) return {};

	try {
		const decoded = decodeURIComponent(cookieValue);
		const parsed = JSON.parse(decoded);
		return parsed.w;
	} catch (e) {
		console.error(e);
		return {};
	}
}

export function getCookieValueFromMockResponses(
	mockResponseIds: UniqueMockId[],
	scenario?: ScenarioStep,
	overrides?: ResponseObjectOverrides,
): string {
	const w = overrides && Object.keys(overrides).length > 0 ? overrides : undefined;
	const mockCDO = {
		r: mockResponseIds ?? [],
		s: scenario ? { ...scenario, mockResponses: undefined } : undefined,
		w,
	};

	try {
		return encodeURIComponent(JSON.stringify(mockCDO));
	} catch {
		return encodeURIComponent('{r:[],w:{}}');
	}
}

type GetMockResponseOptions = {
	apiPath: ApiPath;
	method: HttpMethod;
	path: string;
	forceMock?: boolean;
	responseId?: MockResponseId;
	responseList?: UniqueMockId[];
};

export function getMockResponse({
	apiPath,
	method,
	path,
	forceMock = false,
	responseId,
	responseList = mergeScenarioAndOverrides(mockScenario.peek()?.mockResponses, mockResponses.peek()),
}: GetMockResponseOptions): MockResponse<any> | undefined {
	const currentResponses = getResponsesByEndpoint(apiPath, method, path);
	if (!currentResponses.length) return undefined;

	if (responseList?.length) {
		const match = currentResponses.find((r) => responseList.includes(r.uniqueId));
		if (match) return match;
	}

	if (forceMock || responseId) {
		if (responseId !== undefined) {
			const match = currentResponses.find((r) => r.responseId === responseId);
			if (match) return match;
		}
		return currentResponses[0];
	}

	return undefined;
}

function isUniqueMockIdArray(arr: unknown): arr is UniqueMockId[] {
	return Array.isArray(arr) && arr.every((x) => typeof x === 'string' && /^\d+-\d+$/.test(x));
}

export function syncMockSignalsFromCookie() {
	const cookies = Object.fromEntries(
		document.cookie.split('; ').map((c) => {
			const [k, v = ''] = c.split('=');
			return [k ?? '', v];
		}),
	);

	const cookieValue = cookies[MOCK_API] ?? '';

	mockResponses.value = getMockResponsesFromCookie(cookieValue);
	mockScenario.value = getMockScenarioFromCookie(cookieValue);
	mockResponseOverrides.value = getMockResponseOverridesFromCookie(cookieValue) ?? {};
}

function statusCodeToMessage(statusCode: number): string {
	switch (statusCode) {
		case 200:
			return 'OK';
		case 201:
			return 'Created';
		case 204:
			return 'No Content';
		case 400:
			return 'Bad Request';
		case 401:
			return 'Unauthorized';
		case 403:
			return 'Forbidden';
		case 404:
			return 'Not Found';
		case 422:
			return 'Invalid arguments';
		case 500:
			return 'Internal Server Error';
		default:
			return 'Unknown Status';
	}
}

export function getResponseWrappedData<T>(data: T, statusCode: number = 200): ResponseWrappedData<T> {
	return {
		result: data,
		status_code: statusCode,
		status_message: statusCodeToMessage(statusCode),
	};
}

export function getErrorResponseWrappedData<T>(
	statusCode: number,
	errors?: ResponseErrorDescription[],
	data?: T,
	description?: string,
): ErrorResponseWrapped<T> {
	return {
		...(data && { result: data }),
		status_code: statusCode,
		status_message: statusCodeToMessage(statusCode),
		...(description && { description }),
		...(errors && { errors }),
	};
}

export function getAllMockEndpoints(): MockEndpoint[] {
	try {
		const modules = import.meta.glob('../../service/**/*.mockapi.ts', { eager: true });
		const endpoints = Object.values(modules as Record<string, { mockEP: MockEndpoint }>).map((mod) => mod.mockEP);

		for (const e of endpoints) {
			for (const r of e.responses) {
				const shortId = createResponseIdMap(r.uniqueId);
				if (typeof r.data === 'object') {
					const map = createResponseObjectMap(r.uniqueId, r.data ?? {});
					r.map = map;
				}
				r.shortId = shortId;
			}
		}

		return endpoints;
	} catch {
		return [];
	}
}

function parseUrlToApiParts(url: string): { apiPath: ApiPath; path: string } | null {
	try {
		const u = new URL(url, 'http://localhost');
		const pathname = u.pathname;

		const match = KNOWN_API_PATHS.find((apiPath) => pathname.startsWith(apiPath));
		if (!match) return null;

		const rest = pathname.slice(match.length) || '/';
		return { apiPath: match, path: rest };
	} catch {
		return null;
	}
}

function mergeScenarioAndOverrides(base?: UniqueMockId[], overrides?: UniqueMockId[]): UniqueMockId[] | undefined {
	if ((!base || base.length === 0) && (!overrides || overrides.length === 0)) return undefined;
	const map = new Map<string, UniqueMockId>();
	if (base) {
		for (const id of base) map.set(id.split('-')[0]!, id);
	}
	if (overrides) {
		for (const id of overrides) map.set(id.split('-')[0]!, id);
	}
	return Array.from(map.values());
}

export function findActiveMockResponse({ method, url, mockConfig }: FindMockOptions): MockResponse<any> | undefined {
	// Regular users in prod will always have no mockConfig and allowedMocking is always false on SSR => quick exit on prod without overhead
	if (!mockConfig && !allowedMocking.peek()) return undefined;

	const urlParts = parseUrlToApiParts(url);
	if (!urlParts) return undefined;

	const { apiPath, path } = urlParts;

	let responseId: MockResponseId | undefined = undefined;

	if (mockConfig?.mockResponse) {
		const maybeId = Number(mockConfig.mockResponse.split('-')[1]);
		if (!Number.isNaN(maybeId)) {
			responseId = maybeId as MockResponseId;
		}
	}

	const scenarioResponses = mockConfig?.scenario?.mockResponses;
	const responseList = mergeScenarioAndOverrides(scenarioResponses, mockConfig?.mockResponses);

	return getMockResponse({
		apiPath,
		method,
		path,
		forceMock: mockConfig?.forceMock,
		responseId,
		responseList,
	});
}

export function mergeMockConfig(overrideConfig?: MockConfig, defaultConfig?: MockConfig): MockConfig | undefined {
	if (!overrideConfig && !defaultConfig) return undefined;

	return {
		...defaultConfig,
		...overrideConfig,
		mockResponses: overrideConfig?.mockResponses ?? defaultConfig?.mockResponses,
	};
}

/**
 * Starts monitoring cookie changes and automatically syncs mock signals when cookies change.
 * Returns a cleanup function to stop monitoring.
 */
export function startCookieMonitoring(): () => void {
	let lastMockApiValue = getCookieValue(document.cookie, MOCK_API) ?? '';
	let lastLabModeValue = getCookieValue(document.cookie, LAB_MODE_COOKIE) ?? '';

	const intervalId = setInterval(() => {
		const currentMockApiValue = getCookieValue(document.cookie, MOCK_API) ?? '';
		const currentAllowTestsValue = getCookieValue(document.cookie, LAB_MODE_COOKIE) ?? '';

		if (currentMockApiValue !== lastMockApiValue || currentAllowTestsValue !== lastLabModeValue) {
			lastMockApiValue = currentMockApiValue;
			lastLabModeValue = currentAllowTestsValue;
			syncMockSignalsFromCookie();
		}
	}, 1000);

	return () => {
		clearInterval(intervalId);
	};
}
