import { ResponseObjectMap } from 'utils/mockapi/mapping/mapping';

/**
 * A single string character created by String.fromCharCode can be used as a one character string key, that gets
 * correctly serialized and sent over wihtou any issues. 32 is a good starting point as it is the first printable
 * character (space).
 */
export const SAFE_CHAR_START = 32;

/**
 * Creates a dictionary of keys -> shortened keys mappings for the given object.
 */
export function createResponseObjectMap(responseId: string, object: Record<string, any>) {
	if (ResponseObjectMap[responseId]) return ResponseObjectMap[responseId];

	const toMapped = {};
	const fromMapped = {};
	rec(object, toMapped, fromMapped, { v: SAFE_CHAR_START }, []);

	const map = { toMapped, fromMapped };

	ResponseObjectMap[responseId] = map;

	return map;
}

function rec(
	object: Record<string, any>,
	toMapped: Record<string, string | Record<string, string>>,
	fromMapped: Record<string, string | Record<string, string>>,
	counter: { v: number },
	path: string[],
) {
	for (const k of Object.keys(object)) {
		if (object[k] && typeof object[k] === 'object') {
			path.push(k);
			const nestedToMap: Record<string, string> = {};

			toMapped[k] = nestedToMap;
			rec(object[k], nestedToMap, fromMapped, counter, path);
			path.pop();
		} else {
			const mappedKey = String.fromCharCode(counter.v++);
			toMapped[k] = mappedKey;
			path.push(k);
			fromMapped[mappedKey] = path.join('.');
			path.pop();
		}
	}
}
