export type ResponseObjectMapToMapped = Record<string, Record<string, string>>;
export type ResponseObjectMapFromMapped = Record<string, string>;
export type ResponseObjectMapType = Record<
	string,
	{
		toMapped: ResponseObjectMapToMapped;
		fromMapped: ResponseObjectMapFromMapped;
	}
>;

export type ResponseObjectOverrides = Record<string, Record<string, any>>;

/**
 * Global mapping object that contains mapping information for all mocked **responses** in both directions.
 *
 * `fromMapped` says where to apply the shortened key inside the full object, represented as a path with `.` separator
 * denoting nested objects.
 * ```
 * { '$': 'key', '@': 'nestedObject.nestedValue' }
 * ```
 * `toMapped` says how the full key is renamed to a shortened one. The structure is optimized for recursive application
 * of the mapping.
 * ```
 * { key: '$', nestedObject: { nestedValue: '@'} }
 * ```
 */
export const ResponseObjectMap: ResponseObjectMapType = {};
/**
 * Global mapping object that contains mapping information for all mocked **endpoints** in both directions.
 *
 * Contains information about direct 1:1 mapping of **endpoint** IDs to shortened ones and vice versa.
 *
 * `fromMapped`
 * ```
 * { '@': '1-1' }
 * ```
 * `toMapped`
 * ```
 * { '1-1': '@'}
 * ```
 */
export const ResponseIdMap: ResponseIdMapType = { fromMapped: {}, toMapped: {} };
export type ResponseIdMapType = { fromMapped: Record<string, string>; toMapped: Record<string, string> };

/**
 * A single string character created by String.fromCharCode can be used as a one character string key, that gets
 * correctly serialized and sent over wihtou any issues. 32 is a good starting point as it is the first printable
 * character (space).
 */
let charCodeCounter = 32;

export function createResponseIdMap(key: string) {
	if (ResponseIdMap.toMapped[key]) return ResponseIdMap.toMapped[key];
	const mappedKey = String.fromCharCode(charCodeCounter++);

	ResponseIdMap.toMapped[key] = mappedKey;
	ResponseIdMap.fromMapped[mappedKey] = key;

	return mappedKey;
}
